#include<bits/stdc++.h>
using namespace std;
int main()
{
	int t;
	cin>>t;
	while(t--){
		int n,m;
		cin>>n>>m;
		string s1,s2;
		cin>>s1>>s2;
//		if(n>m)cout<<"No\n";
		int l=0,r=0,flagl=0,flagr=0;;
		for(;l<n && r<n;){
			if(s1[l]!=s2[l])flagl=1;
			if(s1[n-r-1]!=s2[m-r-1])flagr=1;
			if(!flagl)l++;
			if(!flagr)r++;
//			cout<<l<<" "<<r<<endl;
			if(flagl&&flagr)break;
		}
		if(l+r>=n)cout<<"Yes\n";
		else cout<<"No\n";
	}
}
